class Solution {
public:
    int islandPerimeter(vector<vector<int>>& g) {
        int m=g.size(), n=g[0].size(), ans=0;
        for(int i=0;i<m;i++) for(int j=0;j<n;j++) if(g[i][j]){
            ans+=4;
            if(i&&g[i-1][j]) ans-=2;
            if(j&&g[i][j-1]) ans-=2;
        }
        return ans;
    }
};

